declare module '*.js?url' {
    const url: string;
    export default url;
}

declare module '*.css' {
    const css: string;
    export default css;
}

declare module '*.png' {
    const url: string;
    export default url;
}

declare module '*.jpg' {
    const url: string;
    export default url;
}

declare module '*.jpeg' {
    const url: string;
    export default url;
}

declare module '*.svg' {
    const url: string;
    export default url;
}
